var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"으음, 도어락 배터리가 다 된 건가? 회의실 문이 안 열리네.","JPN":"あら、ドアロックのバッテリーが切れたのかしら？\\n会議室のドアが開かないわ。","ENG":"Mm, are the door lock batteries dead? I can't enter the meeting room.","TWN":"唔，門鎖沒電了嗎？會議室的門為什麼打不開呢。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIGMA_RAS_GIRL_NULL","text":{"KOREA":"도움이 필요하구나! 자! 내가 충전해줄게!","JPN":"助けが必要なのね！　さあ、私が\\n充電してあげるわ！","ENG":"Need help? Here, let me recharge them.","TWN":"你需要幫忙嗎！來！我幫你充電！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_GIRL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아, 감사합니다.","JPN":"あ、ありがとうございます。","ENG":"Oh, thank you!","TWN":"啊，非常感謝。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"......그런데, 누구니?","JPN":"……ところで、あなたは？","ENG":"But who are you?","TWN":"……不過，你是誰？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"난 시그마야. 아빠를 따라왔어.","JPN":"私は、シグマよ。パパと一緒に来たの。","ENG":"I'm Sigma. I came here with my daddy.","TWN":"我是西格瑪，是和爸爸一起來的。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"응? ......아빠라고?","JPN":"え？……パパって？","ENG":"Huh? Daddy?","TWN":"嗯？……爸爸？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아하, 아버지가 이 회사에서 일하시는구나?","JPN":"ああ、なるほど。お父さんがこの会社で働いてるのね？","ENG":"Aha, your father works here, huh?","TWN":"喔，你爸爸在這個公司上班嗎？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아버지 성함이 어떻게 되시니?","JPN":"お父さんのお名前は？","ENG":"What's your father's name?","TWN":"你的爸爸叫什麼名字？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"아빠 이름? 기억에 없어.","JPN":"パパの名前？　記憶にないんだけど。","ENG":"Daddy's name? I don't remember.","TWN":"爸爸的名字？我不記得了。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"그치만 아빠는 그냥 아빠인 걸로 충분하잖아?","JPN":"でも、パパはパパなんだよ？","ENG":"Daddy is just Daddy. I don't need to know anything else.","TWN":"但爸爸就是爸爸呀？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"으음...... 아무래도 예감이 좋지 않은데......","JPN":"うーん、これは不吉な予感がするわ……","ENG":"Err... I've got a bad feeling about this...","TWN":"呃……預感不太好……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"이럴 땐 경찰에 미아 신고를 하는 게 좋겠지?","JPN":"こういう時は警察に迷子届を出したほうが\\n良いわよね？","ENG":"Maybe I should call the police and report a missing child.","TWN":"我是不是應該先報警？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"자, 꼬마야. 언니 손 잡고 잠깐 따라올래?","JPN":"さあ、おチビちゃん。お姉ちゃんとおてて繋いで\\n一緒に行きましょう？","ENG":"Come on, kiddo. Why don't you come with me?","TWN":"來，小妹妹，跟姐姐一起走吧？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오, 이런! 여기 있었구나! 우리 귀염둥이!","JPN":"おやおや！　ここにいたのか！　うちのかわい子ちゃん！","ENG":"Oooh! There you are, my little girl!","TWN":"喔，天啊！原來你在這裡！小甜心！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"앗! 아빠!","JPN":"あ！　パパ！","ENG":"Ah, Daddy!","TWN":"啊！爸爸！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"회사구경은 재미있니? 사람들은 많이 도와줬고?","JPN":"会社見学は楽しいかい？　みんなのお手伝いも\\nたくさんできたのかな？","ENG":"How did you like the company? Did you find many people to help?","TWN":"參觀公司開心嗎？有沒有幫助別人？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L28_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응, 여긴 도움이 필요한 사람이랑 로봇들이 많아서 즐거워.","JPN":"うん、ここは助けが必要な人やロボットが\\nたくさんいて楽しい♪","ENG":"Yes! This place is filled with people and robots that need help. I love it!","TWN":"嗯，這裡有很多需要幫助的人類和機器人，我好開心。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L29_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"오, 그랬어요? 그럼 이번엔 아빠랑 같이 정비소로 가볼까?","JPN":"おーそうかそうか。なら、今度はパパと一緒に\\n整備所に行ってみるかい？","ENG":"Ooo, you do, don't cha? Now, how'd you like to go take a look at the garage with Daddy?","TWN":"喔，是嗎？那要不要和爸爸去看看維修站？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"좋아!","JPN":"うん！","ENG":"Yes!","TWN":"好啊！"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"아하, 난 또 누군가 했더니 사장님의 따님이신가 보네요.","JPN":"なるほど、誰かと思えば社長の娘さんなのですね。","ENG":"Ah, so she's the Boss's daughter, huh?","TWN":"啊哈，我以為是誰呢，原來是老闆的女兒。"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"KIMHANA_COFFIN_NULL_NULL","text":{"KOREA":"어라? 그게 말이 되나?","JPN":"えっ？　それってありなの？","ENG":"Erm, but how?","TWN":"嗯？這像話嗎？"},"stage":{"bg":"OFFICE","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KIMHANA_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"현장학습이라곤 하셨지만, 굳이 저렇게 방치해둘 필요가 있는 건가요?","JPN":"見学とはいっても、あんなに放ったらかしにしても\\n大丈夫でしょうか。","ENG":"You said a field trip, but is it really safe to leave her alone like that?","TWN":"就算是現場實習，也沒必要這樣擱置吧？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"테라브레인은 관리국의 중요한 전략자산입니다.","JPN":"テラブレインは管理局の重要な戦略資産です。","ENG":"The Terrabrain is an important asset to the Administration.","TWN":"特拉大腦是管理局的重要戰略資源。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그 동안 어떤 일을 겪었는지 데이터를 추출해서 분석하면 큰 도움이 될 텐데요.","JPN":"これまで何があったのかデータ抽出して分析すれば、\\n大いに役立つと思いますが。","ENG":"Why can't you just extract and analyze her data to find out what happened to her?","TWN":"提取資料分析一下它所經歷的事情，應該會有很大幫助。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그건 좀 곤란하네. 저건 아주 예전에 만든 테라브레인의 초기형이라서 말이야.","JPN":"それは困るな。あれは遥か昔につくったテラブレインの\\nプロトタイプだからね。","ENG":"I can't. She's an early type of Terrabrain I made a long time ago.","TWN":"那可不行，它是很久之前製作出來的原始型特拉大腦。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"초기형은 지능이 뛰어나지만, 침식 방호 능력은 떨어지는 고질적인 문제가 있어.","JPN":"プロトタイプは知能面で優れている半面、\\n侵食防護能力は劣るという根本的な問題がある。","ENG":"Those early types were exceptionally intelligent, but they were vulnerable to Corruption rays.","TWN":"原始型的智能雖然很出色，但防侵蝕能力較低。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"때문에 한번 침식파에 오염되면 데이터 손실을 막을 수가 없다네.","JPN":"だから一度侵食波に汚染されてしまうと、\\nデータ損失を防ぐことができない。","ENG":"Once they're contaminated by Corruption rays, their data can't be salvaged.","TWN":"因此只要被侵蝕波污染一次，就不能阻止資料丟失。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"설령 기억이 남는다 해도, 가장 최근에 겪은 기억의 단편적인 편린들일 뿐이겠지.","JPN":"たとえ記憶が残っているとしても、直近の\\n断片的な記憶だけだろう。","ENG":"Even if I manage to extract some data, I doubt there'd be more than a few fragments of her recent memories.","TWN":"即使留有記憶，也都是最近經歷的記憶片段而已。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"기계가 기억상실증에라도 걸렸단 말씀인가요?","JPN":"機械が記憶喪失でも起こしているということですか？","ENG":"Are you saying that machine has amnesia?","TWN":"機器也能患上失憶症嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"정확히는 아무 것도 모르는 어린아이가 된 거라고 봐야지.","JPN":"正確には、何も知らない子どもになったというのが\\n正しいだろう。","ENG":"More accurately, she's turned into a child that's like a blank sheet of paper.","TWN":"準確地說，是變成了一無所知的小孩子。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그런 것치곤 관리자님을 아주 잘 따르던데요.","JPN":"それにしては管理者様にべったりでしたけど。","ENG":"She likes you very well, considering.","TWN":"但我看它很喜歡管理者大人啊。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"사람도 기억을 잃는다고 해서 그 본성까지 변하는 건 아니지 않나?","JPN":"人間も記憶を失ったからって本性まで\\n変わったりはしないだろう？","ENG":"People may lose their memories, but not their instincts. The same goes for her.","TWN":"人即使失去記憶，他的本性卻不會變化不是嗎？"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"테라브레인은 본질적으로 관리자를 따르도록 설계되어 있네.","JPN":"テラブレインは基本的に管理者に従うように設計されている。","ENG":"The Terrabrain is programmed to follow the Administrator.","TWN":"特拉大腦的本質就是追隨管理者。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만......","JPN":"だが……","ENG":"I just...","TWN":"但是……"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이면세계에서 어떻게 가족이란 개념을 습득한 건지는, 나도 모르겠군.","JPN":"裏世界でどうやって家族という概念を\\n習得したかは、私にもわからないな。","ENG":"I just don't know how she learned the concept of family while in the Counterside.","TWN":"我也不知道它在異界是怎麼學到家人概念的。"},"stage":{"bg":"OFFICE_TOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"자, 착하지? 앞으로는 언니 말 잘 들어야 돼.","JPN":"さあ、いい子ね？　これからはお姉ちゃんの言うことを\\nよーくきくのよ。","ENG":"Now, be a dear and listen to me from now on, okay?","TWN":"乖，以後要好好聽姐姐的話喔。"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"저어...... 고장 난 승강기는 그렇게 쓰다듬는다고 고쳐지는 게 아닌데요......","JPN":"あの……壊れたエレベーターを撫でたところで\\n直ったりはしないのですよ……？","ENG":"Erm, I don't think you can fix broken elevators by patting them...","TWN":"那個……光靠撫摸是修理不了損壞的電梯的……"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"헉! 지, 진짜로 다시 움직이네?!","JPN":"えっ！　ほ、本当に直ってる！？","ENG":"*Gasp* I-it's moving again!","TWN":"啊！這，真的修好了？！"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"물론이지!","JPN":"当たり前だよ！","ENG":"Of course!","TWN":"當然啦！"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"기계들은 다들 착해. 부탁해주면 힘을 내거든.","JPN":"機械はみんないい子なのよ。お願いすると頑張ってくれるの。","ENG":"All machines are good. They listen to you when you ask them nicely.","TWN":"機器都很善良，真誠地請求可以使它們發揮力量。"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"으음, 정비 기계 님......?","JPN":"ええと、機械整備士さん……？","ENG":"Erm, Miss Repair Machine?","TWN":"唔，機器維修大人……？"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"잘 부탁 드려요?","JPN":"どうぞよろしくお願いしますなのです。","ENG":"I hope you don't mind helping me again... and again.","TWN":"請多多關照？"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"하하! 어린 아가씨가 대단하군!","JPN":"ハハ！　まだ小さいお嬢ちゃんなのにすごい\\nじゃないか！","ENG":"Hah hah! You're impressive, young lady!","TWN":"哈哈！小妹妹妳真厲害！"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_30"},{"id":"L25_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"나중에 내 무릎 관절의 반중력 발생장치도 좀 봐주면 좋겠는걸?","JPN":"後で吾輩の膝関節の反重力発生装置も\\n見てくれないか！","ENG":"Maybe you could take a look at the anti-gravity generators in my kneecaps later.","TWN":"下次能抽空幫我看一下我的膝關節上的反重力產生裝置嗎？"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"엄청 크다!","JPN":"うわぁ、巨人だ！","ENG":"You're so huge!","TWN":"好大！"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"할아버지는 누구야?","JPN":"おじいちゃんはだあれ？","ENG":"Who are you, grandpa?","TWN":"爺爺是誰？"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음?! 할아버지?","JPN":"む！？　おじいちゃんだと？","ENG":"Huh? Grandpa?","TWN":"嗯？！爺爺？"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_21"},{"id":"L29_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"난 타이탄이라고 한단다! 세기말 결전병기라고도 불리지.","JPN":"吾輩はタイタンだ！　世紀末決戦兵器とも呼ばれている。","ENG":"I'm Titan. Some people also call me the Ultimate Doomsday Weapon.","TWN":"我叫泰坦！是世紀末決戰兵器。"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"......결전병기가 뭔데?","JPN":"……決戦兵器って、なあに？","ENG":"What does the Ultimate Doomsday Weapon do?","TWN":"……什麼是決戰兵器？"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음! 좋은 질문이로군!","JPN":"うむ！　素晴らしい質問だ！","ENG":"Mm, good question.","TWN":"嗯！問得好！"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"어떤 친구가 누구의 도움도 받을 수 없을 만큼 어려운 위기에 처했을 때! 나만큼은 그 친구를 구해줄 수 있다는 뜻이라네!","JPN":"友人が絶体絶命の危機に瀕した時に！　\\n吾輩だけはそのお友達を助けてあげられるということだ！","ENG":"When someone is in such a dire situation that no one can help them, at least I, the Ultimate Doomsday Weapon, have a chance to help.","TWN":"當有一個朋友陷入生死危機，任何人都無法挽救時！我就會現身救出那個陷入危險的朋友！"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"오오, 멋지다! 그럼 나도 결전병기 할래!","JPN":"おお、カッコイイ！　じゃあ私も決戦兵器になる！","ENG":"Ooo, that sounds awesome! I want to be an Ultimate Doomsday Weapon, too!","TWN":"噢噢，好厲害！我也要成為決戰兵器！"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"음! 좋아! 결전병기는 많으면 많을수록 좋지!","JPN":"うむ！　いいぞ！　決戦兵器は多ければ多いほど良い！","ENG":"Mm! Sure! The more Ultimate Doomsday Weapons, the better!","TWN":"嗯！好！決戰兵器越多越好啦！"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"꼬마 아가씨가 위험해지면 내가 돕고, 내가 위험해지면 꼬마 아가씨가 날 도와주는 거지!","JPN":"お嬢ちゃんが危険な時は吾輩が助け、吾輩が\\n危険な時はお嬢ちゃんに助けてもらおう！","ENG":"When you're in danger, I'll help you. And when I'm in danger, you can help me.","TWN":"小妹妹遇到危險時由我來救，如果我遇到危險，小妹妹就要救我！"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"응! 그렇게 할게! 약속이야!","JPN":"うん！　そうする！　約束よ！","ENG":"Okay! Let's do that! It's a promise!","TWN":"嗯！一定！說好了！"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"아니, 여긴 들어오시면 안 된다고 했잖아요!","JPN":"ちょっと！　ここは入っちゃいけないって言ったのです！","ENG":"Argh, I told you not to come in here!","TWN":"哎，我不是說過你不能到這裡來嗎！"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_TOUCH"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"그렇게 돌아다니면 하중을 못 이겨서 바닥이 꺼진다니까요?","JPN":"そんなに歩き回られると、重さに耐え切れず\\n床が抜けちゃうのですー！","ENG":"The floor can't handle you walking around on it.","TWN":"你這樣到處跑，地板無法承受你的重量的！"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"미안하네! 하지만 날 수송기에 실을 격납장치에 문제가 생겨서 말이야!","JPN":"すまない！　だが吾輩を輸送機まで運ぶ格納装置に\\n問題が生じてな！","ENG":"I'm sorry, but there's a problem with the containment system used to load me onto the ship.","TWN":"對不起！不過負責把我搬到運輸機上的機庫出現問題了！"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"TITAN_FAW_NULL_NULL","text":{"KOREA":"조금 있으면 정기 순찰 임무를 나갈 시간이라 곤란하군! 자네가 좀 도와주지 않겠나?","JPN":"もうすぐ巡察任務の時間だから困っていたんだ！　\\n手伝ってもらえないだろうか？","ENG":"And I'm about to go out on regular patrol duty. Could you please help me?","TWN":"馬上就要到出去執行定期巡查任務的時間了！你能不能幫幫我？"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"으음...... 어쩔 수 없죠.","JPN":"うーん……仕方ないですね。","ENG":"Mm... Okay.","TWN":"嗯……只好這樣了。"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"NAHEERIN_COFFIN_NULL_NULL","text":{"KOREA":"바닥에 충격 가지 않게 살살 걸어오세요.","JPN":"床に荷重をかけないように、そーっと\\n来てくださいなのです。","ENG":"But you'd better walk as carefully as you can.","TWN":"小心，別把地板弄壞了。"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NAHEERIN_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TITAN_FAW_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"SIGMA_RAS_NULL_NULL","text":{"KOREA":"나도! 나도 도울게!","JPN":"私も！　私も手伝う！","ENG":"Me! Let me help!","TWN":"我也要！我也要幫忙！"},"stage":{"bg":"HANGAR","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"OFFICE_TOP","bgm":"UI_BASE_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SIGMA_RAS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};